// Revisión técnica solar — cascade IA gratuita → pago.
// Cascade: Groq (Llama 3.3 70B) → Gemini 1.5 Flash → Mistral Small → Claude Haiku → Claude Sonnet
// Env: GROQ_API_KEY, GOOGLE_AI_KEY, MISTRAL_API_KEY, ANTHROPIC_API_KEY
// Input body: { context: 'review'|'sizing'|'explain', payload: {...} }

const src = $input.first().json;
const body = src.body || src;
const context = (body.context || 'review').toString();
const payload = body.payload || {};

const SYSTEM = 'Eres un ingeniero eléctrico especializado en sistemas solares fotovoltaicos en Colombia. Conoces RETIE, CREG 038/2014, CREG 174/2021 (AGPE), Ley 1715, estándares NEC/IEC. Analiza el dimensionamiento que te envía el cotizador y devuelve observaciones concretas, accionables y técnicas. Usa español neutro.';

const USER_PROMPT = `Contexto: ${context}\n\nSistema a revisar (JSON):\n${JSON.stringify(payload, null, 2)}\n\nDevuelve SOLO JSON válido con esta forma exacta (sin markdown):\n{\n  \"summary\": string,\n  \"findings\": string[],\n  \"warnings\": string[],\n  \"suggestions\": string[]\n}\n\nReglas:\n- summary: 1-2 frases, lenguaje ejecutivo.\n- findings: 2-5 observaciones técnicas clave (dimensionamiento, cobertura, compatibilidad eléctrica, normativa).\n- warnings: alertas críticas (voc fuera de rango, banco subdimensionado, incompatibilidad de voltaje, excedentes fuera de AGPE, etc). Vacío si no hay.\n- suggestions: 2-4 acciones recomendadas específicas.\n- NO inventes valores. Trabaja solo con los datos del payload.`;

function extractJSON(text) {
  const m = text.match(/\{[\s\S]*\}/);
  if (!m) return null;
  try { return JSON.parse(m[0]); } catch { return null; }
}

function normalize(parsed, provider, tokens) {
  return {
    summary: parsed.summary || '',
    findings: Array.isArray(parsed.findings) ? parsed.findings : [],
    warnings: Array.isArray(parsed.warnings) ? parsed.warnings : [],
    suggestions: Array.isArray(parsed.suggestions) ? parsed.suggestions : [],
    provider,
    tokens: tokens || {},
  };
}

// --- 1) Groq — Llama 3.3 70B (14,400 req/day gratis) ---
const GROQ_KEY = $env.GROQ_API_KEY;
if (GROQ_KEY) {
  try {
    const r = await this.helpers.httpRequest({
      method: 'POST',
      url: 'https://api.groq.com/openai/v1/chat/completions',
      headers: { 'Authorization': `Bearer ${GROQ_KEY}`, 'Content-Type': 'application/json' },
      body: {
        model: 'llama-3.3-70b-versatile',
        max_tokens: 1200,
        temperature: 0.1,
        messages: [
          { role: 'system', content: SYSTEM },
          { role: 'user', content: USER_PROMPT },
        ],
      },
      json: true,
      returnFullResponse: true,
      ignoreHttpStatusErrors: true,
    });
    if (r.statusCode === 200) {
      const text = r.body.choices?.[0]?.message?.content || '';
      const parsed = extractJSON(text);
      if (parsed) {
        const u = r.body.usage || {};
        return [{ json: normalize(parsed, 'groq/llama-3.3-70b', { in: u.prompt_tokens || 0, out: u.completion_tokens || 0 }) }];
      }
    }
  } catch {}
}

// --- 2) Gemini 1.5 Flash (1,500 req/day gratis) ---
const GKEY = $env.GOOGLE_AI_KEY;
if (GKEY) {
  try {
    const r = await this.helpers.httpRequest({
      method: 'POST',
      url: `https://generativelanguage.googleapis.com/v1beta/models/gemini-1.5-flash:generateContent?key=${GKEY}`,
      headers: { 'Content-Type': 'application/json' },
      body: {
        contents: [{ parts: [{ text: `${SYSTEM}\n\n${USER_PROMPT}` }] }],
        generationConfig: { maxOutputTokens: 1200, temperature: 0.1 },
      },
      json: true,
      returnFullResponse: true,
      ignoreHttpStatusErrors: true,
    });
    if (r.statusCode === 200) {
      const text = r.body.candidates?.[0]?.content?.parts?.[0]?.text || '';
      const parsed = extractJSON(text);
      if (parsed) {
        const u = r.body.usageMetadata || {};
        return [{ json: normalize(parsed, 'gemini-1.5-flash', { in: u.promptTokenCount || 0, out: u.candidatesTokenCount || 0 }) }];
      }
    }
  } catch {}
}

// --- 3) Mistral Small (free tier) ---
const MISTRAL_KEY = $env.MISTRAL_API_KEY;
if (MISTRAL_KEY) {
  try {
    const r = await this.helpers.httpRequest({
      method: 'POST',
      url: 'https://api.mistral.ai/v1/chat/completions',
      headers: { 'Authorization': `Bearer ${MISTRAL_KEY}`, 'Content-Type': 'application/json' },
      body: {
        model: 'mistral-small-latest',
        max_tokens: 1200,
        temperature: 0.1,
        messages: [
          { role: 'system', content: SYSTEM },
          { role: 'user', content: USER_PROMPT },
        ],
      },
      json: true,
      returnFullResponse: true,
      ignoreHttpStatusErrors: true,
    });
    if (r.statusCode === 200) {
      const text = r.body.choices?.[0]?.message?.content || '';
      const parsed = extractJSON(text);
      if (parsed) {
        const u = r.body.usage || {};
        return [{ json: normalize(parsed, 'mistral-small', { in: u.prompt_tokens || 0, out: u.completion_tokens || 0 }) }];
      }
    }
  } catch {}
}

// --- 4) Claude Haiku (pago, más económico) ---
const AKEY = $env.ANTHROPIC_API_KEY;
if (AKEY) {
  try {
    const r = await this.helpers.httpRequest({
      method: 'POST',
      url: 'https://api.anthropic.com/v1/messages',
      headers: { 'x-api-key': AKEY, 'anthropic-version': '2023-06-01', 'content-type': 'application/json' },
      body: {
        model: 'claude-haiku-4-5-20251001',
        max_tokens: 1200,
        system: SYSTEM,
        messages: [{ role: 'user', content: USER_PROMPT }],
      },
      json: true,
      returnFullResponse: true,
      ignoreHttpStatusErrors: true,
    });
    if (r.statusCode === 200) {
      const text = (r.body.content || []).map(c => c.text || '').join('\n').trim();
      const parsed = extractJSON(text);
      if (parsed) {
        const u = r.body.usage || {};
        return [{ json: normalize(parsed, 'claude-haiku-4-5', { in: u.input_tokens || 0, out: u.output_tokens || 0 }) }];
      }
    }
  } catch {}
}

// --- 5) Claude Sonnet (pago, máxima capacidad — último recurso) ---
if (!AKEY) {
  throw new Error('Ningún proveedor IA configurado. Configura GROQ_API_KEY, GOOGLE_AI_KEY, MISTRAL_API_KEY o ANTHROPIC_API_KEY.');
}
const sonnet = await this.helpers.httpRequest({
  method: 'POST',
  url: 'https://api.anthropic.com/v1/messages',
  headers: { 'x-api-key': AKEY, 'anthropic-version': '2023-06-01', 'content-type': 'application/json' },
  body: {
    model: 'claude-sonnet-4-6',
    max_tokens: 1200,
    system: SYSTEM,
    messages: [{ role: 'user', content: USER_PROMPT }],
  },
  json: true,
});
const finalText = (sonnet.content || []).map(c => c.text || '').join('\n').trim();
const finalParsed = extractJSON(finalText);
if (!finalParsed) throw new Error('Claude Sonnet no devolvió JSON parseable');
const fu = sonnet.usage || {};
return [{ json: normalize(finalParsed, 'claude-sonnet-4-6', { in: fu.input_tokens || 0, out: fu.output_tokens || 0 }) }];
